const logger = new DebugLogger();

// Enhanced fetch wrapper for network logging
const originalFetch = global.fetch;

global.fetch = function(...args) {
  const startTime = Date.now();
  const url = args[0];
  const options = args[1];
  
  const request = {
    url,
    method: options?.method || 'GET',
    headers: options?.headers,
    body: options?.body
  };
  
  return originalFetch(...args)
    .then(response => {
      const duration = Date.now() - startTime;
      logger.logNetworkRequest(
        request.url,
        request.method,
        request.body,
        {
          status: response.status,
          statusText: response.statusText,
          headers: response.headers,
          url: response.url
        },
        duration
      );
      return response;
    })
    .catch(error => {
      const duration = Date.now() - startTime;
      logger.logNetworkRequest(
        request.url,
        request.method,
        request.body,
        { error: error.message },
        duration
      );
      throw error;
    });
};

// Enhanced AsyncStorage wrapper for logging
const originalAsyncStorage = AsyncStorage;

AsyncStorage.getItem = function(key) {
  const startTime = Date.now();
  return originalAsyncStorage.getItem(key)
    .then(result => {
      logger.logAsyncStorageOperation('GET', key, null, result);
      return result;
    })
    .catch(error => {
      logger.logAsyncStorageOperation('GET', key, null, { error: error.message });
      throw error;
    });
};

AsyncStorage.setItem = function(key, value) {
  const startTime = Date.now();
  return originalAsyncStorage.setItem(key, value)
    .then(result => {
      logger.logAsyncStorageOperation('SET', key, value, result);
      return result;
    })
    .catch(error => {
      logger.logAsyncStorageOperation('SET', key, value, { error: error.message });
      throw error;
    });
};

AsyncStorage.removeItem = function(key) {
  const startTime = Date.now();
  return originalAsyncStorage.removeItem(key)
    .then(result => {
      logger.logAsyncStorageOperation('REMOVE', key, null, result);
      return result;
    })
    .catch(error => {
      logger.logAsyncStorageOperation('REMOVE', key, null, { error: error.message });
      throw error;
    });
};

export default logger;